SIGSEGV发生的情况包括： NULL指针访问 指针被破坏等原因导致的非法地址访问 栈溢出导致访问超出了已分配的地址空间 Resource deadlock avoidedn #include &lt;iostream&gt;#include &lt;vector&gt;#include &lt;thread&gt;#include &lt;condition_variable&gt;#include &lt;functional&gt;#include &lt;deque&gt;#include &lt;future&gt;#include &lt;type_traits&gt;#include &lt;memory&gt;#include &lt;chrono&gt;#include &lt;assert.h&gt;using namespace std;class Barrier &#123;public: explicit Barrier(std::size_t thread_count) : thread_count_(thread_count), waiting_(0), step_(0) &#123;&#125; void wait() &#123; auto current_step = step_.load(std::memory_order_relaxed); if (waiting_.fetch_add(1, std::memory_order_acquire) + 1 == thread_count_) &#123; // 最后一个线程到达屏障，重置等待计数，并进入下一步 waiting_.store(0, std::memory_order_relaxed); step_.fetch_add(1, std::memory_order_release); &#125; else &#123; // 等待其他线程到达 while (step_.load(std::memory_order_acquire) == current_step) &#123; // 自旋等待 std::this_thread::yield(); // 让出 CPU 时间片，避免完全忙等待 &#125; &#125; &#125;private: const std::size_t thread_count_; // 线程总数 std::atomic&lt;std::size_t&gt; waiting_; // 当前等待的线程数 std::atomic&lt;std::size_t&gt; step_; // 用于区分不同的屏障周期&#125;;class WaitGroup &#123;public: WaitGroup(int n) :count_&#123; n &#125; &#123;&#125; void Done() &#123; count_.fetch_sub(1, memory_order_acq_rel); &#125; void Wait() &#123; int n; while ((n = count_.load(memory_order_acquire)) &gt; 0) &#123; // cout &lt;&lt; &quot;n = &quot; &lt;&lt; n &lt;&lt; endl; this_thread::yield(); &#125; &#125;private: atomic&lt;int&gt; count_;&#125;;class ThreadPool &#123;public: enum Signal &#123; STOP, IGNORE &#125;; explicit ThreadPool(unsigned n) &#123; Spawn(n); &#125; ~ThreadPool() &#123; Destroy(); &#125; void Destroy() &#123; &#123; lock_guard&lt;mutex&gt; guard&#123; tasks_mtx_ &#125;; for (size_t i = 0; i &lt; thread_group_.size(); ++i) &#123; tasks_.emplace_back([] &#123; return STOP; &#125;); &#125; &#125; tasks_cv_.notify_all(); for (auto&amp; td : thread_group_) &#123; td.join(); &#125; &#125; template &lt;typename Fn, typename... Args&gt; auto async_execute(Fn&amp;&amp; fn, Args&amp;&amp;... args) &#123; using R = invoke_result_t&lt;Fn, Args...&gt;; shared_ptr&lt;promise&lt;R&gt;&gt; sp = make_shared&lt;promise&lt;R&gt;&gt;(); future&lt;R&gt; result = sp-&gt;get_future(); &#123; lock_guard&lt;mutex&gt; guard&#123; tasks_mtx_ &#125;; tasks_.push_back([_fn = std::forward&lt;Fn&gt;(fn), ..._args = std::forward&lt;Args&gt;(args), _sp=sp]() &#123; if constexpr (is_void_v&lt;R&gt;) &#123; invoke(_fn, _args...); _sp-&gt;set_value(); &#125; else &#123; R ret = invoke(_fn, _args...); _sp-&gt;set_value(ret); &#125; return IGNORE; &#125;); tasks_cv_.notify_one(); &#125; return result; &#125;private: void Spawn(unsigned n) &#123; for (unsigned i = 0; i &lt; n; i++) &#123; thread_group_.emplace_back([this]() &#123; bool is_stopped = false; while (!is_stopped) &#123; function&lt;Signal()&gt; task; &#123; unique_lock&lt;mutex&gt; lock_guard&#123; tasks_mtx_ &#125;; tasks_cv_.wait(lock_guard, [this]() &#123; return !tasks_.empty(); &#125;); task = std::move(tasks_.front()); tasks_.pop_front(); tasks_cv_.notify_one(); &#125; // Execute the task without lock. auto signal = task(); if (signal == STOP) &#123; is_stopped = true; &#125; &#125; &#125;); &#125; &#125; vector&lt;thread&gt; thread_group_; deque&lt;function&lt;Signal()&gt;&gt; tasks_; mutex tasks_mtx_; condition_variable tasks_cv_;&#125;;class TaskGraph &#123;public: TaskGraph() &#123; AddNode([]() &#123; cout &lt;&lt; &quot;This is sink: dadada
&quot;; &#125;); &#125; template &lt;typename Fn, typename... Args&gt; int AddNode(Fn&amp;&amp; fn, Args&amp;&amp;... args) &#123; int id = unique_id_++; nodes_.emplace_back(id, [_fn = std::forward&lt;Fn&gt;(fn), ..._args = std::forward&lt;Args&gt;(args)]() &#123; _fn(_args...); &#125;); return id; &#125; void Execute(ThreadPool&amp; executor) &#123; AddSource(); AddSink(executor); // Dump(); int n = nodes_.size(); WaitGroup wg&#123; n &#125;; Schedule(nodes_.front(), executor, wg); wg.Wait(); &#125; void Dump() const &#123; for (const auto&amp; node : nodes_) &#123; DumpNode(node); &#125; &#125;private: struct Node &#123; Node(int id, const function&lt;void()&gt;&amp; func) : id &#123; id &#125;, npredecessor&#123; new atomic&lt;int&gt;&#123;&#125; &#125;, task&#123; func &#125; &#123;&#125; void operator()() &#123; task(); &#125; int id; atomic&lt;int&gt;* npredecessor; vector&lt;int&gt; successors; string name; function&lt;void()&gt; task; &#125;; void AddSource() &#123; auto&amp; source = nodes_[0]; for (int i = 1; i &lt; nodes_.size(); i++) &#123; source.successors.push_back(nodes_[i].id); nodes_[i].npredecessor-&gt;operator++(); &#125; &#125; void AddSink(ThreadPool&amp; executor) &#123; AddNode([&amp;executor]() &#123; executor.Destroy(); &#125;); auto&amp; sink = nodes_.back(); for (int i = 0; i &lt; nodes_.size() - 1; i++) &#123; nodes_[i].successors.push_back(sink.id); sink.npredecessor-&gt;operator++(); &#125; &#125; void Schedule(Node&amp; node, ThreadPool&amp; executor, WaitGroup&amp; wg) &#123; executor.async_execute([&amp;node, &amp;executor, &amp;wg, this]() &#123; node(); for (auto sid : node.successors) &#123; auto count = nodes_[sid].npredecessor-&gt;fetch_sub(1); if (count == 1) &#123; Schedule(nodes_[sid], executor, wg); &#125; &#125; wg.Done(); &#125;); &#125; void DumpNode(const Node&amp; node) const &#123; cout &lt;&lt; &quot;# of Predecessors: &quot; &lt;&lt; node.npredecessor-&gt;load() &lt;&lt; &#x27;
&#x27;; cout &lt;&lt; &quot;# of Successors: &quot; &lt;&lt; node.successors.size() &lt;&lt; &#x27;
&#x27;; for (auto sid : node.successors) &#123; cout &lt;&lt; &quot; &quot; &lt;&lt; sid &lt;&lt; &#x27;
&#x27;; &#125; cout &lt;&lt; endl; &#125; int unique_id_&#123;&#125;; vector&lt;Node&gt; nodes_;&#125;;class Taskflow &#123;public: Taskflow(unsigned nthreads) : pool_&#123; nthreads &#125; &#123;&#125; template &lt;typename Fn, typename... Args&gt; int Submit(Fn&amp;&amp; fn, Args&amp;&amp;... args) &#123; return graph_.AddNode(std::forward&lt;Fn&gt;(fn), std::forward&lt;Args&gt;(args)...); &#125; void WaitAll() &#123; graph_.Execute(pool_); &#125; void Visualize() &#123; graph_.Dump(); &#125;private: TaskGraph graph_; ThreadPool pool_;&#125;;int add(int a, int b) &#123; return a + b;&#125;void foo() &#123; // this_thread::sleep_for(chrono::seconds(5)); cout &lt;&lt; &quot;foo
&quot;;&#125;void worker(int id, Barrier&amp; barrier) &#123; std::cout &lt;&lt; &quot;Thread &quot; &lt;&lt; id &lt;&lt; &quot; before barrier
&quot;; barrier.wait(); std::cout &lt;&lt; &quot;Thread &quot; &lt;&lt; id &lt;&lt; &quot; after barrier
&quot;;&#125;int main(int argc, char** argv) &#123; Taskflow tf&#123; 1 &#125;; tf.Submit(foo); tf.Submit(add, 1, 2); tf.WaitAll(); cout &lt;&lt; &quot;end of main
